import React from 'react';
import Box from '@mui/material/Box';
import Button from '@mui/material/Button';
import FormControl from '@mui/material/FormControl';
import InputLabel from '@mui/material/InputLabel';
import MenuItem from '@mui/material/MenuItem';
import Select from '@mui/material/Select';
import Stack from '@mui/material/Stack';
import TextField from '@mui/material/TextField';
import Typography from '@mui/material/Typography';

import * as yup from 'yup';

import AppCard from '../common/AppCard';
import UserAlert from '../common/UserAlert';
import { api } from '../../services/api';
import { useAppDispatch } from '../../store/hooks';
import { showSnackbar } from '../../store/slices/uiSlice';

type Props = {
  articleId: number;
  defaultSubject: string;
};

type Values = {
  recipients: string;
  subject: string;
  type: 'new_article' | 'update';
};

const schema: yup.ObjectSchema<Values> = yup
  .object({
    recipients: yup.string().required('Destinataires obligatoires'),
    subject: yup.string().required('Sujet obligatoire').min(3, 'Sujet: min 3 caractères'),
    type: yup.mixed<Values['type']>().oneOf(['new_article', 'update']).required(),
  })
  .required();

function parseRecipients(raw: string): string[] {
  return raw
    .split(/[,\n;]/g)
    .map((s) => s.trim())
    .filter((s) => s.includes('@'));
}

export default function NotifyArticleCard({ articleId, defaultSubject }: Props) {
  const dispatch = useAppDispatch();
  const [values, setValues] = React.useState<Values>({ recipients: '', subject: defaultSubject, type: 'new_article' });
  const [fieldErrors, setFieldErrors] = React.useState<Record<string, string>>({});
  const [busy, setBusy] = React.useState(false);
  const [error, setError] = React.useState<string | null>(null);

  const validate = async (): Promise<boolean> => {
    try {
      await schema.validate(values, { abortEarly: false });
      setFieldErrors({});
      return true;
    } catch (e) {
      const next: Record<string, string> = {};
      if (e instanceof yup.ValidationError) {
        for (const err of e.inner) {
          if (err.path && !next[err.path]) next[err.path] = err.message;
        }
      }
      setFieldErrors(next);
      return false;
    }
  };

  const send = async () => {
    setError(null);

    const ok = await validate();
    if (!ok) return;

    const recipients = parseRecipients(values.recipients);
    if (!recipients.length) {
      setFieldErrors((cur) => ({ ...cur, recipients: 'Au moins un email valide est requis' }));
      return;
    }

    setBusy(true);
    try {
      await api.notifyArticle(articleId, { type: values.type, recipients, subject: values.subject });
      dispatch(showSnackbar({ severity: 'success', message: 'Notification enregistrée.' }));
      setValues((v) => ({ ...v, recipients: '' }));
    } catch {
      setError("Échec de l'envoi/enregistrement de la notification.");
      dispatch(showSnackbar({ severity: 'error', message: "Échec de l'envoi/enregistrement de la notification." }));
    } finally {
      setBusy(false);
    }
  };

  return (
    <AppCard title="Envoyer une notification email">
      <Stack spacing={2}>
        {error ? <UserAlert severity="error" message={error} /> : null}

        <FormControl size="small" sx={{ minWidth: 200 }}>
          <InputLabel id="notify-type">Type</InputLabel>
          <Select
            labelId="notify-type"
            label="Type"
            value={values.type}
            onChange={(e) => setValues((v) => ({ ...v, type: e.target.value as Values['type'] }))}
          >
            <MenuItem value="new_article">new_article</MenuItem>
            <MenuItem value="update">update</MenuItem>
          </Select>
        </FormControl>

        <TextField
          label="Destinataires (séparés par virgule ou saut de ligne)"
          value={values.recipients}
          onChange={(e) => setValues((v) => ({ ...v, recipients: e.target.value }))}
          error={Boolean(fieldErrors.recipients)}
          helperText={fieldErrors.recipients}
          multiline
          minRows={3}
          fullWidth
        />

        <TextField
          label="Sujet"
          value={values.subject}
          onChange={(e) => setValues((v) => ({ ...v, subject: e.target.value }))}
          error={Boolean(fieldErrors.subject)}
          helperText={fieldErrors.subject}
          fullWidth
        />

        <Box sx={{ p: 2, border: '1px solid rgba(0,0,0,0.12)', borderRadius: 1, bgcolor: 'white' }}>
          <Typography variant="subtitle2" gutterBottom>
            Prévisualisation (simple)
          </Typography>
          <Typography variant="body2">
            {values.subject}
          </Typography>
          <Typography variant="caption" color="text.secondary">
            Le contenu HTML final est généré côté serveur.
          </Typography>
        </Box>

        <Stack direction="row" justifyContent="flex-end">
          <Button aria-label="Envoyer notification" variant="contained" onClick={send} disabled={busy}>
            Envoyer
          </Button>
        </Stack>
      </Stack>
    </AppCard>
  );
}
