import type { Article, Category, Network } from '../types/entities';

export type ListArticlesParams = {
  query?: string;
  categoryIds?: number[];
  featured?: boolean;
  status?: 'draft' | 'published' | 'archived';
  networkId?: number;
  page?: number;
  pageSize?: number;
  sort?: 'publishedAt' | 'title' | 'createdAt';
  order?: 'asc' | 'desc';
};

export type ImportArticleJsonItem = {
  title: string;
  content: string;
  excerpt?: string;
  author?: string;
  category: string;
  network: string;
};

export type ImportResultItem = {
  index: number;
  ok: boolean;
  articleId?: number;
  errors?: { field: string; message: string }[];
};

export type ImportArticlesResponse = {
  total: number;
  successCount: number;
  errorCount: number;
  items: ImportResultItem[];
};

export type NotificationHistoryItem = {
  id: number;
  userId: number;
  articleId: number;
  articleTitle: string;
  type: 'new_article' | 'update';
  subject: string | null;
  status: 'sent' | 'failed';
  error: string | null;
  recipientsCount: number;
  sentAt: string;
};

export type CreateCategoryInput = {
  name: string;
  description: string;
  networkId: number;
};

export type UpdateCategoryInput = {
  name?: string;
  description?: string;
  networkId?: number;
};

export type DashboardResponse = {
  totals: {
    articles: number;
  };
  byStatus: Record<string, number>;
  byNetwork: { networkId: number; count: number }[];
  byCategory: { categoryId: number; name: string; count: number }[];
  latestPublished: { id: number; title: string; publishedAt: string | null; networkId: number }[];
  latestNotifications: { id: number; userId: number; articleId: number; type: string; sentAt: string }[];
};

export type PaginatedResult<T> = {
  items: T[];
  total: number;
  page: number;
  pageSize: number;
};

export type CreateArticleInput = {
  title: string;
  content: string;
  status: 'draft' | 'published' | 'archived';
  featured: boolean;
  publishedAt?: string | null;
  categoryIds: number[];
  networkId: number;
  authorId?: number;
};

export type UpdateArticleInput = {
  title?: string;
  content?: string;
  status?: 'draft' | 'published' | 'archived';
  featured?: boolean;
  publishedAt?: string | null;
  categoryIds?: number[];
  networkId?: number;
  authorId?: number;
};

const API_BASE_URL = process.env.REACT_APP_API_BASE_URL ?? 'http://localhost:3002/api';

async function request<T>(path: string, init?: RequestInit): Promise<T> {
  const res = await fetch(`${API_BASE_URL}${path}`, {
    headers: {
      'Content-Type': 'application/json',
      ...(init?.headers ?? {}),
    },
    ...init,
  });

  if (!res.ok) {
    throw new Error(`API error ${res.status}`);
  }

  return (await res.json()) as T;
}

export const api = {
  listArticles: (params?: ListArticlesParams): Promise<PaginatedResult<Article>> => {
    const sp = new URLSearchParams();

    if (params?.query) sp.set('query', params.query);
    if (params?.categoryIds?.length) sp.set('categoryIds', params.categoryIds.join(','));
    if (params?.featured !== undefined) sp.set('featured', String(params.featured));
    if (params?.status) sp.set('status', params.status);
    if (params?.networkId !== undefined) sp.set('networkId', String(params.networkId));
    if (params?.page !== undefined) sp.set('page', String(params.page));
    if (params?.pageSize !== undefined) sp.set('pageSize', String(params.pageSize));
    if (params?.sort) sp.set('sort', params.sort);
    if (params?.order) sp.set('order', params.order);

    const q = sp.toString();
    return request<PaginatedResult<Article>>(`/articles${q ? `?${q}` : ''}`);
  },

  getArticle: (id: number): Promise<Article> => request<Article>(`/articles/${id}`),

  createArticle: (input: CreateArticleInput): Promise<Article> =>
    request<Article>('/articles', {
      method: 'POST',
      body: JSON.stringify(input),
    }),

  updateArticle: (id: number, input: UpdateArticleInput): Promise<Article> =>
    request<Article>(`/articles/${id}`, {
      method: 'PUT',
      body: JSON.stringify(input),
    }),

  deleteArticle: (id: number): Promise<void> =>
    request<void>(`/articles/${id}`, {
      method: 'DELETE',
    }),

  patchArticleStatus: (id: number, status: 'draft' | 'published' | 'archived'): Promise<Article> =>
    request<Article>(`/articles/${id}/status`, {
      method: 'PATCH',
      body: JSON.stringify({ status }),
    }),

  notifyArticle: (
    id: number,
    input: { type: 'new_article' | 'update'; recipients: string[]; subject?: string }
  ): Promise<{ message: string }> =>
    request<{ message: string }>(`/articles/${id}/notify`, {
      method: 'POST',
      body: JSON.stringify(input),
    }),

  listNotifications: (): Promise<NotificationHistoryItem[]> => request<NotificationHistoryItem[]>('/notifications'),

  listCategories: (): Promise<Category[]> => request<Category[]>('/categories'),
  getCategory: (id: number): Promise<Category> => request<Category>(`/categories/${id}`),
  createCategory: (input: CreateCategoryInput): Promise<Category> =>
    request<Category>('/categories', {
      method: 'POST',
      body: JSON.stringify(input),
    }),
  updateCategory: (id: number, input: UpdateCategoryInput): Promise<Category> =>
    request<Category>(`/categories/${id}`, {
      method: 'PUT',
      body: JSON.stringify(input),
    }),
  deleteCategory: (id: number): Promise<void> =>
    request<void>(`/categories/${id}`, {
      method: 'DELETE',
    }),
  listNetworks: (): Promise<Network[]> => request<Network[]>('/networks'),

  getDashboard: (params?: { networkId?: number }): Promise<DashboardResponse> => {
    const sp = new URLSearchParams();
    if (params?.networkId !== undefined) sp.set('networkId', String(params.networkId));
    const q = sp.toString();
    return request<DashboardResponse>(`/dashboard${q ? `?${q}` : ''}`);
  },

  importArticles: (items: ImportArticleJsonItem[]): Promise<ImportArticlesResponse> =>
    request<ImportArticlesResponse>('/import/articles', {
      method: 'POST',
      body: JSON.stringify(items),
    }),
};
