import type { ArticleFormValues } from '../components/articles/ArticleForm';

const PREFIX = 'taram:draft:';

export function getDraftKey(params: { mode: 'create' | 'edit'; articleId?: number }) {
  return params.mode === 'edit' && typeof params.articleId === 'number' ? `${PREFIX}${params.articleId}` : `${PREFIX}new`;
}

export function loadDraft(key: string): { values: ArticleFormValues; savedAt: string } | null {
  try {
    const raw = localStorage.getItem(key);
    if (!raw) return null;
    const parsed = JSON.parse(raw) as { values: ArticleFormValues; savedAt: string };
    if (!parsed?.values || typeof parsed?.savedAt !== 'string') return null;
    return parsed;
  } catch {
    return null;
  }
}

export function saveDraft(key: string, values: ArticleFormValues) {
  const payload = { values, savedAt: new Date().toISOString() };
  localStorage.setItem(key, JSON.stringify(payload));
  return payload.savedAt;
}

export function clearDraft(key: string) {
  localStorage.removeItem(key);
}
