import React from 'react';
import Container from '@mui/material/Container';
import Stack from '@mui/material/Stack';
import { useNavigate, useParams } from 'react-router-dom';

import UserAlert from '../components/common/UserAlert';
import ArticleForm, { ArticleFormValues } from '../components/articles/ArticleForm';
import NotifyArticleCard from '../components/articles/NotifyArticleCard';
import { api, CreateArticleInput, UpdateArticleInput } from '../services/api';
import type { Article, Category, Network } from '../types/entities';
import { clearDraft, getDraftKey, loadDraft, saveDraft } from '../utils/draft';
import { showSnackbar } from '../store/slices/uiSlice';
import { useAppDispatch } from '../store/hooks';

type Props = {
  mode: 'create' | 'edit';
  articleId?: number;
};

export default function ArticleEditor({ mode, articleId }: Props) {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const params = useParams();
  const routeArticleId = params.id ? Number(params.id) : undefined;
  const resolvedArticleId = typeof articleId === 'number' ? articleId : routeArticleId;

  const [article, setArticle] = React.useState<Article | undefined>(undefined);
  const [categories, setCategories] = React.useState<Category[]>([]);
  const [networks, setNetworks] = React.useState<Network[]>([]);
  const [error, setError] = React.useState<string | null>(null);
  const [loading, setLoading] = React.useState(false);

  const draftKey = React.useMemo(
    () => getDraftKey({ mode, articleId: resolvedArticleId }),
    [mode, resolvedArticleId]
  );

  const [draftValues, setDraftValues] = React.useState<ArticleFormValues | null>(null);
  const [dirty, setDirty] = React.useState(false);
  const lastSavedRef = React.useRef<string | null>(null);

  React.useEffect(() => {
    let mounted = true;
    setError(null);
    setLoading(true);

    const promises: Promise<unknown>[] = [
      api.listCategories().then((cats) => {
        if (!mounted) return;
        setCategories(cats);
      }),
      api.listNetworks().then((nets) => {
        if (!mounted) return;
        setNetworks(nets);
      }),
    ];

    if (mode === 'edit' && typeof resolvedArticleId === 'number' && Number.isFinite(resolvedArticleId)) {
      promises.push(
        api.getArticle(resolvedArticleId).then((a) => {
          if (!mounted) return;
          setArticle(a);
        })
      );
    } else {
      setArticle(undefined);
    }

    Promise.all(promises)
      .catch(() => {
        if (!mounted) return;
        setError('Impossible de charger les données de l\'éditeur.');
      })
      .finally(() => {
        if (!mounted) return;
        setLoading(false);
      });

    return () => {
      mounted = false;
    };
  }, [mode, resolvedArticleId]);

  React.useEffect(() => {
    const loaded = loadDraft(draftKey);
    if (!loaded) {
      setDraftValues(null);
      setDirty(false);
      return;
    }

    setDraftValues(loaded.values);
    setDirty(true);
    lastSavedRef.current = loaded.savedAt;
  }, [draftKey]);

  React.useEffect(() => {
    const id = window.setInterval(() => {
      if (!dirty || !draftValues) return;
      const savedAt = saveDraft(draftKey, draftValues);
      lastSavedRef.current = savedAt;
      dispatch(showSnackbar({ severity: 'info', message: 'Brouillon auto-sauvegardé.' }));
    }, 30_000);
    return () => window.clearInterval(id);
  }, [dirty, draftValues, draftKey, dispatch]);

  const handleSubmit = async (values: ArticleFormValues) => {
    setError(null);

    if (values.networkId === '') {
      throw new Error('Invalid form');
    }

    if (mode === 'create') {
      const input: CreateArticleInput = {
        title: values.title,
        content: values.content,
        status: values.status,
        featured: values.featured,
        categoryIds: values.categoryIds,
        networkId: values.networkId,
      };

      await api.createArticle(input);
      dispatch(showSnackbar({ severity: 'success', message: 'Article créé.' }));
      clearDraft(draftKey);
      setDirty(false);
      return;
    }

    if (typeof resolvedArticleId !== 'number' || !Number.isFinite(resolvedArticleId)) {
      throw new Error('Missing articleId');
    }

    const input: UpdateArticleInput = {
      title: values.title,
      content: values.content,
      status: values.status,
      featured: values.featured,
      categoryIds: values.categoryIds,
      networkId: values.networkId,
    };

    await api.updateArticle(resolvedArticleId, input);
    dispatch(showSnackbar({ severity: 'success', message: 'Article mis à jour.' }));
    clearDraft(draftKey);
    setDirty(false);
  };

  return (
    <Container maxWidth="lg" sx={{ py: 4 }}>
      <Stack spacing={2}>
        {error ? <UserAlert severity="error" message={error} /> : null}
        {loading ? <UserAlert severity="info" message="Chargement..." /> : null}
        <ArticleForm
          mode={mode}
          initialArticle={draftValues ? ({ ...(article ?? ({} as any)), ...draftValues, id: article?.id } as any) : article}
          categories={categories}
          networks={networks}
          onCancel={() => navigate(-1)}
          onSubmit={handleSubmit}
          onChange={(v) => {
            setDraftValues(v);
            setDirty(true);
          }}
        />

        {dirty ? <UserAlert severity="warning" message="Modifications non sauvegardées (brouillon local)." /> : null}

        {mode === 'edit' && typeof resolvedArticleId === 'number' && article ? (
          <NotifyArticleCard
            articleId={resolvedArticleId}
            defaultSubject={`Nouvel article: ${article.title}`}
          />
        ) : null}
      </Stack>
    </Container>
  );
}
