import React from 'react';
import Box from '@mui/material/Box';
import FormControl from '@mui/material/FormControl';
import InputLabel from '@mui/material/InputLabel';
import MenuItem from '@mui/material/MenuItem';
import Select from '@mui/material/Select';
import Stack from '@mui/material/Stack';
import Switch from '@mui/material/Switch';
import TextField from '@mui/material/TextField';
import Typography from '@mui/material/Typography';

import * as yup from 'yup';

import ActionButton from '../common/ActionButton';
import AppCard from '../common/AppCard';
import UserAlert from '../common/UserAlert';
import { Status } from '../../types/entities';
import type { Article, Category, Network } from '../../types/entities';

export type ArticleFormValues = {
  title: string;
  content: string;
  status: Status;
  featured: boolean;
  networkId: number | '';
  categoryIds: number[];
};

type Props = {
  mode: 'create' | 'edit';
  initialArticle?: Article;
  categories: Category[];
  networks: Network[];
  onSubmit: (values: ArticleFormValues) => Promise<void>;
  onCancel: () => void;
  onChange?: (values: ArticleFormValues) => void;
};

const schema: yup.ObjectSchema<ArticleFormValues> = yup
  .object({
    title: yup.string().required('Titre obligatoire').min(5, 'Titre: min 5 caractères'),
    content: yup.string().required('Contenu obligatoire').min(50, 'Contenu: min 50 caractères'),
    status: yup
      .mixed<ArticleFormValues['status']>()
      .oneOf([Status.DRAFT, Status.PUBLISHED, Status.ARCHIVED])
      .required(),
    featured: yup.boolean().required(),
    networkId: yup
      .number()
      .typeError('Réseau obligatoire')
      .required('Réseau obligatoire'),
    categoryIds: yup
      .array()
      .of(yup.number().required())
      .min(1, 'Sélectionne au moins une catégorie')
      .required('Sélectionne au moins une catégorie'),
  })
  .required();

function toValues(article?: Article): ArticleFormValues {
  return {
    title: article?.title ?? '',
    content: article?.content ?? '',
    status: article?.status ?? ('draft' as any),
    featured: article?.featured ?? false,
    networkId: article?.networkId ?? '',
    categoryIds: article?.categoryIds ?? [],
  };
}

export default function ArticleForm({ mode, initialArticle, categories, networks, onSubmit, onCancel, onChange }: Props) {
  const [values, setValues] = React.useState<ArticleFormValues>(() => toValues(initialArticle));
  const [submitting, setSubmitting] = React.useState(false);
  const [submitError, setSubmitError] = React.useState<string | null>(null);
  const [fieldErrors, setFieldErrors] = React.useState<Record<string, string>>({});

  React.useEffect(() => {
    onChange?.(values);
  }, [values, onChange]);

  React.useEffect(() => {
    setValues(toValues(initialArticle));
    setSubmitError(null);
    setFieldErrors({});
  }, [initialArticle]);

  const validate = async (): Promise<boolean> => {
    try {
      await schema.validate(values, { abortEarly: false });
      setFieldErrors({});
      return true;
    } catch (e) {
      const next: Record<string, string> = {};
      if (e instanceof yup.ValidationError) {
        for (const err of e.inner) {
          if (err.path && !next[err.path]) next[err.path] = err.message;
        }
      }
      setFieldErrors(next);
      return false;
    }
  };

  const handleSubmit = async () => {
    setSubmitError(null);
    const ok = await validate();
    if (!ok) return;

    setSubmitting(true);
    try {
      await onSubmit(values);
    } catch {
      setSubmitError("Impossible d'enregistrer l'article.");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <AppCard title={mode === 'create' ? 'Créer un article' : `Modifier l'article #${initialArticle?.id ?? ''}`}> 
      <Stack spacing={2}>
        {submitError ? <UserAlert severity="error" message={submitError} /> : null}

        <Stack direction={{ xs: 'column', md: 'row' }} spacing={2}>
          <TextField
            label="Titre"
            value={values.title}
            onChange={(e) => setValues((v) => ({ ...v, title: e.target.value }))}
            error={Boolean(fieldErrors.title)}
            helperText={fieldErrors.title}
            fullWidth
            size="small"
          />

          <FormControl size="small" sx={{ minWidth: 160 }} error={Boolean(fieldErrors.status)}>
            <InputLabel id="status-select">Status</InputLabel>
            <Select
              labelId="status-select"
              label="Status"
              value={values.status}
              onChange={(e) => setValues((v) => ({ ...v, status: e.target.value as any }))}
            >
              <MenuItem value="draft">draft</MenuItem>
              <MenuItem value="published">published</MenuItem>
              <MenuItem value="archived">archived</MenuItem>
            </Select>
          </FormControl>

          <Stack direction="row" spacing={1} alignItems="center" sx={{ pl: { md: 1 } }}>
            <Typography variant="body2">Featured</Typography>
            <Switch
              checked={values.featured}
              onChange={(e) => setValues((v) => ({ ...v, featured: e.target.checked }))}
            />
          </Stack>
        </Stack>

        <Stack direction={{ xs: 'column', md: 'row' }} spacing={2}>
          <FormControl size="small" sx={{ minWidth: 220 }} error={Boolean(fieldErrors.networkId)}>
            <InputLabel id="network-select">Réseau</InputLabel>
            <Select
              labelId="network-select"
              label="Réseau"
              value={values.networkId}
              onChange={(e) => {
                const v = String(e.target.value);
                setValues((cur) => ({ ...cur, networkId: v === '' ? '' : Number(v) }));
              }}
            >
              <MenuItem value="">Sélectionner</MenuItem>
              {networks.map((n) => (
                <MenuItem key={n.id} value={n.id}>
                  {n.name}
                </MenuItem>
              ))}
            </Select>
            {fieldErrors.networkId ? (
              <Typography variant="caption" color="error">
                {fieldErrors.networkId}
              </Typography>
            ) : null}
          </FormControl>

          <FormControl size="small" sx={{ minWidth: 320 }} error={Boolean(fieldErrors.categoryIds)}>
            <InputLabel id="categories-select">Catégories</InputLabel>
            <Select
              labelId="categories-select"
              label="Catégories"
              multiple
              value={values.categoryIds as any}
              onChange={(e) => {
                const v = e.target.value as number[];
                setValues((cur) => ({ ...cur, categoryIds: v }));
              }}
            >
              {categories.map((c) => (
                <MenuItem key={c.id} value={c.id}>
                  {c.name}
                </MenuItem>
              ))}
            </Select>
            {fieldErrors.categoryIds ? (
              <Typography variant="caption" color="error">
                {fieldErrors.categoryIds}
              </Typography>
            ) : null}
          </FormControl>
        </Stack>

        <TextField
          label="Contenu"
          value={values.content}
          onChange={(e) => setValues((v) => ({ ...v, content: e.target.value }))}
          error={Boolean(fieldErrors.content)}
          helperText={fieldErrors.content}
          fullWidth
          multiline
          minRows={6}
        />

        <Box>
          <Typography variant="subtitle2" gutterBottom>
            Aperçu
          </Typography>
          <Box sx={{ p: 2, border: '1px solid rgba(0,0,0,0.12)', borderRadius: 1, bgcolor: 'white' }}>
            <Typography variant="h6" gutterBottom>
              {values.title || '—'}
            </Typography>
            <Typography variant="body2" sx={{ whiteSpace: 'pre-wrap' }}>
              {values.content || '—'}
            </Typography>
          </Box>
        </Box>

        <Stack direction="row" spacing={1} justifyContent="flex-end">
          <ActionButton label="Annuler" onClick={onCancel} disabled={submitting} />
          <ActionButton
            label={mode === 'create' ? 'Créer' : 'Enregistrer'}
            onClick={handleSubmit}
            disabled={submitting}
          />
        </Stack>
      </Stack>
    </AppCard>
  );
}
